import type { ScaleQuantize, ScaleThreshold } from 'd3-scale';

import { SCALE_FALLBACK_COLOR } from '../../../core/constants.js';
import type { XYChartColorScale } from '../../types/xy-chart-internals.js';

export const getColorFromNumericScale = (
  colorScale: XYChartColorScale,
  value: number,
): string => {
  const colorDomain = colorScale.domain();
  const [min, max] = [
    colorDomain[0] as number,
    colorDomain[colorDomain.length - 1] as number,
  ];
  if (value >= min && value <= max) {
    const scale = colorScale as
      | ScaleQuantize<string>
      | ScaleThreshold<number, string>;
    return scale(value);
  }

  return SCALE_FALLBACK_COLOR;
};
